              >
                <svg className="size-3.5" viewBox="0 0 14 14" fill="none" stroke="currentColor" strokeWidth="1.5">
                  <path d="M1 3h12M3 7h8M5 11h4" strokeLinecap="round" />
                </svg>
                Filter
                {filterLicensorIds.size > 0 && (
                  <span
                    className="flex size-4 items-center justify-center rounded-full text-[10px] font-bold text-white"
                    style={{ background: '#0094FF' }}
                  >
                    {filterLicensorIds.size}
                  </span>
                )}
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="max-h-[70vh] w-56 overflow-y-auto">
              <DropdownMenuLabel>Licensor</DropdownMenuLabel>
              <input
                value={licensorQuery}
                onChange={(e) => setLicensorQuery(e.target.value)}
                onKeyDown={(e) => e.stopPropagation()}
                placeholder="Search licensors…"
                className="mx-2 mb-1 w-[calc(100%-1rem)] rounded-md border px-2 py-1 text-[12.5px] outline-none focus:border-[#0094FF]"
                style={{ borderColor: '#EAEEF5', color: '#1B2840' }}
              />
              {licensors
                .filter((l) => (l.name ?? '').toLowerCase().includes(licensorQuery.trim().toLowerCase()))
                .map((l) => (
                <DropdownMenuCheckboxItem
                  key={l.id}
                  checked={filterLicensorIds.has(l.id)}
                  onCheckedChange={() => toggleLicensor(l.id)}
                  onSelect={(e) => e.preventDefault()}
                >
                  {l.name}
                </DropdownMenuCheckboxItem>
              ))}
              {licensors.length === 0 && (
                <div className="px-2 py-1.5 text-[12px]" style={{ color: '#94A0B5' }}>
                  No licensors loaded
                </div>
              )}
            </DropdownMenuContent>
          </DropdownMenu>

          {/* Color */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <button
                className="flex items-center gap-1.5 rounded-[10px] border px-3.5 py-2 text-[13px] font-medium transition-colors hover:bg-[#F6F8FC]"
                style={{ borderColor: '#EAEEF5', color: '#5A6883' }}
              >
                <svg className="size-3.5" viewBox="0 0 14 14" fill="none">
                  <circle cx="4" cy="4" r="2.5" fill="#4F9DF7" />
                  <circle cx="10" cy="4" r="2.5" fill="#F0564B" />
                  <circle cx="4" cy="10" r="2.5" fill="#3F9A50" />
                  <circle cx="10" cy="10" r="2.5" fill="#F59E0B" />
                </svg>
                Color
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-44">
              <DropdownMenuLabel>Color cards by</DropdownMenuLabel>
              <DropdownMenuRadioGroup value={colorBy} onValueChange={(v) => setColorBy(v as ColorBy)}>
                {COLOR_OPTIONS.map((o) => (
                  <DropdownMenuRadioItem key={o.value} value={o.value}>{o.label}</DropdownMenuRadioItem>
                ))}
              </DropdownMenuRadioGroup>
            </DropdownMenuContent>
          </DropdownMenu>

          {/* Save current filters as a view */}
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <button
                className="flex items-center gap-1.5 rounded-[10px] px-3.5 py-2 text-[13px] font-semibold text-white transition-colors"
                style={{ background: '#0094FF' }}
              >
                <Plus className="size-3.5" />
                Save view
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-64 p-3">
              <DropdownMenuLabel className="p-0 pb-2">Save current filters as a view</DropdownMenuLabel>
              <input
                value={saveName}
                onChange={(e) => setSaveName(e.target.value)}
                onKeyDown={(e) => { if (e.key === 'Enter') saveView() }}
                placeholder="View name"
                className="mb-2 w-full rounded-lg border px-2.5 py-1.5 text-[13px] outline-none"
                style={{ borderColor: '#EAEEF5', color: '#1B2840' }}
                autoFocus
              />
              <label className="mb-2 flex cursor-pointer items-center gap-2 text-[12.5px]" style={{ color: '#5A6883' }}>
                <input type="checkbox" checked={saveShared} onChange={(e) => setSaveShared(e.target.checked)} className="size-3.5" />
                Share with the whole company
              </label>
              <button
                onClick={saveView}
                disabled={!saveName.trim() || saving}
                className="w-full rounded-lg py-1.5 text-[13px] font-semibold text-white transition-colors disabled:opacity-40"
                style={{ background: '#0094FF' }}
              >
                {saving ? 'Saving…' : `Save to ${businessUnit}`}
              </button>
            </DropdownMenuContent>
          </DropdownMenu>
        </>
      )}

      {/* User avatar */}
      <button
        className="flex size-9 shrink-0 items-center justify-center rounded-full text-[13px] font-bold text-white"
        style={{ background: 'linear-gradient(135deg,#FF9F43,#F47B20)' }}
        title={user?.email ?? undefined}
      >
        {initials}
      </button>
    </header>
  )
}

